// 增强特性：摄像头错误处理、请求防抖、断线保护、节流控制

let cameraStream = null;
let isScanning = false;
let scanInterval = null;
let pendingFaceRequests = new Set(); // 防止人脸识别请求堆积

// ==================== 增强型 Fetch（与 main.js 共享模式）====================

async function fetchWithTimeout(url, options = {}, timeoutMs = 8000) {
    const controller = new AbortController();
    const id = setTimeout(() => controller.abort(), timeoutMs);
    const requestKey = url + JSON.stringify(options.body || '');

    if (pendingFaceRequests.has(requestKey)) {
        console.warn('Duplicate face request blocked:', url);
        return null;
    }
    pendingFaceRequests.add(requestKey);

    try {
        const response = await fetch(url, { ...options, signal: controller.signal });
        clearTimeout(id);
        return response;
    } catch (error) {
        clearTimeout(id);
        if (error.name === 'AbortError') {
            console.warn('Face request timeout:', url);
        }
        return null;
    } finally {
        pendingFaceRequests.delete(requestKey);
    }
}

async function apiGet(url, timeoutMs = 8000) {
    try {
        const response = await fetchWithTimeout(url, {}, timeoutMs);
        if (!response) return null;
        return await response.json();
    } catch (e) {
        console.error('API GET error:', e);
        return null;
    }
}

async function apiPost(url, data, timeoutMs = 8000) {
    try {
        const response = await fetchWithTimeout(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        }, timeoutMs);
        if (!response) return null;
        return await response.json();
    } catch (e) {
        console.error('API POST error:', e);
        return null;
    }
}

document.addEventListener('DOMContentLoaded', () => {
    updateClock();
    setInterval(updateClock, 1000);
    loadPersons();
    loadAccessLogs();
});

function updateClock() {
    const now = new Date();
    const el = document.getElementById('currentTime');
    const locale = I18N.currentLang === 'zh' ? 'zh-CN' : 'en-US';
    if (el) el.textContent = now.toLocaleTimeString(locale, { hour12: false });
}

function showNotification(message, type = 'info') {
    const el = document.getElementById('notification');
    if (!el) return;
    el.textContent = message;
    el.className = `notification ${type} show`;
    setTimeout(() => { el.className = 'notification hidden'; }, 3000);
}

// ==================== 摄像头控制（增强错误处理）====================

async function startCamera() {
    const video = document.getElementById('faceVideo');
    const overlay = document.getElementById('faceOverlay');
    const indicator = document.getElementById('faceIndicator');
    const scanRing = document.getElementById('scanningRing');

    if (!video || !overlay || !indicator || !scanRing) {
        showNotification('页面元素未就绪', 'error');
        return;
    }

    if (cameraStream) {
        stopCamera();
        return;
    }

    try {
        cameraStream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: 'user', width: 640, height: 480 }
        });
        video.srcObject = cameraStream;
        video.style.display = 'block';
        overlay.style.display = 'none';

        // 更新按钮文字
        const btn = document.querySelector('[data-i18n="access.camera_start"]');
        if (btn) {
            const lang = I18N.currentLang;
            btn.textContent = lang === 'zh' ? '\u5173\u95ed\u6444\u50cf\u5934' : 'Stop Camera';
        }

        indicator.style.display = 'flex';
        scanRing.classList.add('active');

        showNotification(
            I18N.currentLang === 'zh' ? '\u6444\u50cf\u5934\u5df2\u542f\u52a8\uff0c\u5f00\u59cb\u5b9e\u65f6\u4eba\u8138\u8bc6\u522b' : 'Camera started, real-time face recognition active',
            'success'
        );

        startRealtimeScanning();

    } catch (err) {
        console.error('Camera error:', err);
        let msg;
        if (err.name === 'NotAllowedError') {
            msg = I18N.currentLang === 'zh' ? '\u672a\u83b7\u5f97\u6444\u50cf\u5934\u6743\u9650\uff0c\u8bf7\u5728\u6d4f\u89c8\u5668\u8bbe\u7f6e\u4e2d\u5141\u8bb8\u8bbf\u95ee' : 'Camera permission denied. Please allow in browser settings';
        } else if (err.name === 'NotFoundError') {
            msg = I18N.currentLang === 'zh' ? '\u672a\u627e\u5230\u6444\u50cf\u5934\u8bbe\u5907' : 'No camera device found';
        } else {
            msg = (I18N.currentLang === 'zh' ? '\u65e0\u6cd5\u8bbf\u95ee\u6444\u50cf\u5934: ' : 'Cannot access camera: ') + err.message;
        }
        showNotification(msg, 'error');
    }
}

function stopCamera() {
    if (cameraStream) {
        cameraStream.getTracks().forEach(track => track.stop());
        cameraStream = null;
    }

    const video = document.getElementById('faceVideo');
    const overlay = document.getElementById('faceOverlay');
    const indicator = document.getElementById('faceIndicator');
    const scanRing = document.getElementById('scanningRing');

    if (video) { video.srcObject = null; video.style.display = 'none'; }
    if (overlay) overlay.style.display = 'flex';
    if (indicator) indicator.style.display = 'flex';
    if (scanRing) scanRing.classList.remove('active');

    const btn = document.querySelector('[data-i18n="access.camera_start"]');
    if (btn) {
        const lang = I18N.currentLang;
        btn.textContent = lang === 'zh' ? '\u542f\u52a8\u6444\u50cf\u5934' : 'Start Camera';
    }

    if (scanInterval) {
        clearInterval(scanInterval);
        scanInterval = null;
    }
    isScanning = false;

    showNotification(
        I18N.currentLang === 'zh' ? '\u6444\u50cf\u5934\u5df2\u5173\u95ed' : 'Camera stopped',
        'info'
    );
}

// 页面卸载时自动关闭摄像头，防止内存泄漏
window.addEventListener('beforeunload', () => {
    if (cameraStream) {
        cameraStream.getTracks().forEach(track => track.stop());
    }
    if (scanInterval) clearInterval(scanInterval);
});

// ==================== 实时人脸扫描（带防抖节流）====================

function startRealtimeScanning() {
    const video = document.getElementById('faceVideo');
    const canvas = document.getElementById('faceCanvas');
    if (!video || !canvas) return;

    const ctx = canvas.getContext('2d');
    canvas.width = 640;
    canvas.height = 480;

    // 每3秒发送一帧（比之前的2秒更宽松，减少请求压力）
    scanInterval = setInterval(async () => {
        if (!cameraStream || isScanning || !navigator.onLine) return;
        isScanning = true;

        try {
            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
            const imageData = canvas.toDataURL('image/jpeg', 0.8);

            const res = await fetchWithTimeout('/api/face/recognize', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ image: imageData })
            }, 10000);

            if (!res) {
                // 请求超时或失败，静默处理，不中断扫描
                isScanning = false;
                return;
            }

            const result = await res.json();
            if (result && result.detected && result.face_id) {
                handleFaceResult(result);
            }
        } catch (e) {
            console.error('Face scan error:', e);
        } finally {
            isScanning = false;
        }
    }, 3000);
}

async function handleFaceResult(result) {
    const indicator = document.getElementById('faceIndicator');
    const resultEl = document.getElementById('accessResult');
    if (!indicator || !resultEl) return;

    const res = await apiPost('/api/access/verify', {
        face_id: result.face_id,
        verify_type: 'face'
    }, 5000);

    if (!res) return;

    if (res.granted) {
        indicator.innerHTML = `
            <svg viewBox="0 0 24 24" fill="none" stroke="#00e676" stroke-width="2" style="width:24px;height:24px">
                <path d="M20 6L9 17l-5-5"/>
            </svg>
            <span style="color:#00e676">${res.person} - ${I18N.currentLang === 'zh' ? '\u5df2\u8bc6\u522b' : 'Recognized'}</span>
        `;
        resultEl.textContent = res.message;
        resultEl.className = 'access-result granted';
        showNotification(
            I18N.currentLang === 'zh' ? `\u4eba\u8138\u9a8c\u8bc1\u901a\u8fc7: ${res.person}` : `Face verified: ${res.person}`,
            'success'
        );
    } else {
        indicator.innerHTML = `
            <svg viewBox="0 0 24 24" fill="none" stroke="#ff1744" stroke-width="2" style="width:24px;height:24px">
                <circle cx="12" cy="12" r="10"/>
                <line x1="15" y1="9" x2="9" y2="15"/>
                <line x1="9" y1="9" x2="15" y2="15"/>
            </svg>
            <span style="color:#ff1744">${I18N.currentLang === 'zh' ? '\u672a\u6388\u6743\u4eba\u5458' : 'Unauthorized'}</span>
        `;
        resultEl.textContent = res.message;
        resultEl.className = 'access-result denied';
        showNotification(t('notify.access_denied'), 'error');
    }
    loadAccessLogs();
}

